+    // Continuous batching: adjust based on available memory
+    // Check if we're on Apple Silicon (ARM) - GPU/CPU share unified memory
+    const is_apple_silicon = builtin.cpu.arch == .aarch64 and builtin.os.tag == .macos;
+    if (is_apple_silicon) {
+        std.debug.print("🍎 Apple Silicon detected: unified memory (no separate VRAM)\n", .{});
+    }
+
+    // KV cache is the main memory consumer after model weights
+    // For 32B Q2_K (~12GB model), we need to be very conservative on 16GB systems
+    // Reserve more headroom for OS, scratch buffers, and system prompt processing
+    const available_for_kv = @max(0.5, mem_stats.available_gb - 2.0); // Reserve 2GB for OS/scratch
+
+    // Estimate KV cache size per token based on model size and KV type
+    // These are approximate values for typical 32B models (~64 layers, 5120 embd)
+    const bytes_per_token: f64 = switch (kv_type) {
+        .q4_0 => 0.3 * 1024 * 1024, // ~300KB per token
+        .q8_0 => 0.6 * 1024 * 1024, // ~600KB per token
+        .fp16 => 1.2 * 1024 * 1024, // ~1.2MB per token
+    };
+
+    // Calculate max total context we can afford
+    const max_affordable_ctx: u32 = @intFromFloat(@max(512, (available_for_kv * 1024 * 1024 * 1024) / bytes_per_token));
+
+    // For 16GB systems, be very conservative:
+    // - Use only 1 cell (Claude Code sends multiple requests, but process sequentially)
+    // - This ensures all memory goes to one request at a time
+    const max_cells: u32 = if (mem_stats.total_gb <= 18.0) 1 else if (available_for_kv < 4.0) 1 else if (available_for_kv < 8.0) 2 else 4;
+
+    // Divide context budget across cells, cap at reasonable per-cell limit
+    // For single cell on 16GB, give it the full budget
+    const context_per_cell = @min(final_ctx, @min(8192, max_affordable_ctx / max_cells));
+
+    // Also reduce batch size on low memory to prevent OOM during prefill
+    const effective_batch_size: u32 = if (mem_stats.total_gb <= 18.0)
+        @min(256, prof.optimal_config.n_batch) // Smaller batches on 16GB
+    else
+        @min(prof.optimal_config.n_batch, context_per_cell);
+
+    std.debug.print("Memory budget: {d:.1}GB available for KV cache\n", .{available_for_kv});
+    std.debug.print("Continuous batching: {} cell(s) x {} tokens/cell (batch_size={})\n", .{
+        max_cells, context_per_cell, effective_batch_size
+    });

